-- Seed customers/products from customer product Excel
-- Run after reset/create schema

ON CONFLICT (cust_code) DO UPDATE SET cust_name=EXCLUDED.cust_name, cust_address=EXCLUDED.cust_address, note=EXCLUDED.note;

ON CONFLICT (item_code) DO UPDATE SET
  product_code=EXCLUDED.product_code, product_name=EXCLUDED.product_name, width_cm=EXCLUDED.width_cm,
  width_unit=EXCLUDED.width_unit, thick_mc=EXCLUDED.thick_mc, mat_code=EXCLUDED.mat_code,
  core_weight=EXCLUDED.core_weight, length=EXCLUDED.length, cust_code=EXCLUDED.cust_code;